cells: list = []

cells.append(nbf.v4.new_markdown_cell('# 固定データに対して推論ステップごとにフィットしていく様子をGIF化するノート\n\n"\n    "- **目的**: 前ノートブック `001_statistical_modeling_fit_gifs.ipynb` をコピーし、データ点は全フレームで固定したまま、推論/最適化ステップが進むにつれてモデルがデータに沿っていく様子を GIF にする。\n"\n    "- **対象**:\n"\n    "  1. 単一分布フィッティング: 正規分布の $\\mu, \\sigma$ を最尤推定する。\n"\n    "  2. 単回帰: $y = \\alpha + \\beta x + \\epsilon$ の $\\alpha, \\beta$ を最小二乗で推定する。\n"\n    "- **可視化方針**: データは最初から全件表示し、各 frame では現在の推論ステップの推定分布/推定線と、その step のブートストラップ 90% 帯を描く。\n"\n    "- **作成環境**: `D:/dev/dev_statistics/venv` の venv kernel (`Python (dev_statistics venv)`)。\n"\n    "- **作成物**: `outputs/gifs/05_fixed_data_normal_inference_steps.gif`, `outputs/gifs/06_fixed_data_linear_inference_steps.gif`。\n"\n'))

cells.append(nbf.v4.new_markdown_cell('## 0. データとモデルの前提\n\n今回も軽量で再現しやすい `seaborn-data` の Palmer Penguins を使う。ただし、ノートブック実行時に外部 URL へアクセスせず、ローカル保存済みの [`data/raw/penguins.csv`](../data/raw/penguins.csv) を読み込む。元データの出典 URL は [`data/SOURCES.md`](../data/SOURCES.md) にまとめた。\n\n| 可視化 | データ | 目的変数/対象 | モデル | 推論ステップ |\n|---|---|---|---|---|\n| 1. 単一分布フィット | Palmer Penguins | `body_mass_g` | $y \\sim \\mathcal{N}(\\mu, \\sigma^2)$ | 標準化後の負の対数尤度を Adam で最小化 |\n| 2. 単回帰 | Palmer Penguins | `body_mass_g` vs `flipper_length_mm` | $y = \x07lpha + \x08eta x + \\epsilon$ | 標準化後の MSE を Adam で最小化 |\n\nどちらも **データは固定** で、推論ステップごとのモデル状態だけが変化する。\n'))

cells.append(nbf.v4.new_code_cell('# 1. Imports / paths / theme\nfrom __future__ import annotations\n\nimport warnings\nfrom pathlib import Path\nimport imageio.v2 as imageio\nimport japanize_matplotlib\nimport matplotlib\n\nmatplotlib.use("Agg")  # GIF generation is file-based and restartable\n\nimport matplotlib.pyplot as plt\nimport numpy as np\nimport pandas as pd\nimport seaborn as sns\nfrom scipy.stats import norm\n\nwarnings.filterwarnings("ignore", category=RuntimeWarning)\nwarnings.filterwarnings("ignore", category=UserWarning)\n\nsns.set_theme(style="whitegrid", palette="muted", font_scale=1.05)\njapanize_matplotlib.japanize()\nplt.rcParams["figure.dpi"] = 110\nplt.rcParams["savefig.dpi"] = 120\nplt.rcParams["axes.unicode_minus"] = False\n\nPROJECT_ROOT = Path.cwd()\nif PROJECT_ROOT.name == "notebooks":\n    PROJECT_ROOT = PROJECT_ROOT.parent\n\nDATA_DIR = PROJECT_ROOT / "data" / "raw"\nGIF_DIR = PROJECT_ROOT / "outputs" / "gifs"\nFIG_DIR = PROJECT_ROOT / "outputs" / "figures"\nfor path in [DATA_DIR, GIF_DIR, FIG_DIR]:\n    path.mkdir(parents=True, exist_ok=True)\n\nprint(f"PROJECT_ROOT = {PROJECT_ROOT}")\nprint(f"GIF_DIR      = {GIF_DIR}")\n'))

cells.append(nbf.v4.new_code_cell('# 2. Load fixed open data from local CSV\nPENGUINS_CSV = DATA_DIR / "penguins.csv"\nif not PENGUINS_CSV.exists():\n    raise FileNotFoundError(\n        f"{PENGUINS_CSV} が見つかりません。公開データは事前にローカル保存してから実行してください。"\n    )\n\npenguins = pd.read_csv(PENGUINS_CSV)\nprint(f"penguins <- {PENGUINS_CSV.relative_to(PROJECT_ROOT).as_posix()}")\nprint("penguins", penguins.shape, list(penguins.columns))\n'))

cells.append(nbf.v4.new_code_cell('# 3. Shared helper functions\ndef fig_to_frame(fig: matplotlib.figure.Figure) -> np.ndarray:\n    """Convert a Matplotlib figure to an RGB numpy frame for imageio."""\n    fig.canvas.draw()\n    rgba = np.asarray(fig.canvas.buffer_rgba())\n    return rgba[:, :, :3].copy()\n\n\ndef save_gif(frames: list[np.ndarray], path: Path, fps: int = 8) -> Path:\n    path.parent.mkdir(parents=True, exist_ok=True)\n    imageio.mimsave(path, frames, duration=1 / fps, loop=0)\n    print(f"saved {path} ({len(frames)} frames, {fps} fps)")\n    return path\n\n\ndef add_note(ax: plt.Axes, text: str, loc: tuple[float, float] = (0.02, 0.98)) -> None:\n    ax.text(\n        loc[0],\n        loc[1],\n        text,\n        transform=ax.transAxes,\n        va="top",\n        ha="left",\n        fontsize=9,\n        bbox={"boxstyle": "round,pad=0.35", "fc": "white", "ec": "0.75", "alpha": 0.92},\n    )\n\n\ndef normal_nll_per_obs(x_std: np.ndarray, mu: float, log_sigma: float) -> float:\n    sigma = float(np.exp(log_sigma))\n    z = (x_std - mu) / sigma\n    return float(log_sigma + 0.5 * np.mean(z**2) + 0.5 * np.log(2 * np.pi))\n\n\ndef adam_normal_trace(\n    x_std: np.ndarray,\n    n_iter: int = 55,\n    lr: float = 0.11,\n    start_mu: float = -2.2,\n    start_log_sigma: float = np.log(2.2),\n) -> list[tuple[float, float, float]]:\n    """Adam steps for Normal negative log likelihood on standardized data."""\n    params = np.array([start_mu, start_log_sigma], dtype=float)\n    m = np.zeros_like(params)\n    v = np.zeros_like(params)\n    beta1, beta2, eps = 0.9, 0.999, 1e-8\n    trace: list[tuple[float, float, float]] = []\n\n    for step in range(n_iter + 1):\n        mu, log_sigma = float(params[0]), float(params[1])\n        trace.append((mu, log_sigma, normal_nll_per_obs(x_std, mu, log_sigma)))\n\n        sigma = float(np.exp(log_sigma))\n        grad_mu = float(np.mean((mu - x_std) / sigma**2))\n        grad_log_sigma = float(1.0 - np.mean((x_std - mu) ** 2 / sigma**2))\n        grad = np.array([grad_mu, grad_log_sigma], dtype=float)\n\n        m = beta1 * m + (1 - beta1) * grad\n        v = beta2 * v + (1 - beta2) * (grad**2)\n        m_hat = m / (1 - beta1 ** (step + 1))\n        v_hat = v / (1 - beta2 ** (step + 1))\n        params -= lr * m_hat / (np.sqrt(v_hat) + eps)\n        params[1] = float(np.clip(params[1], np.log(0.25), np.log(5.0)))\n    return trace\n\n\ndef normal_density_from_std_params(grid_raw: np.ndarray, center: float, scale: float, mu: float, log_sigma: float) -> np.ndarray:\n    grid_std = (grid_raw - center) / scale\n    sigma = float(np.exp(log_sigma))\n    return norm.pdf(grid_std, loc=mu, scale=sigma) / scale\n\n\ndef normal_bootstrap_trace_bands(\n    x_raw: np.ndarray,\n    grid_raw: np.ndarray,\n    center: float,\n    scale: float,\n    n_iter: int = 55,\n    n_boot: int = 90,\n    seed: int = 0,\n) -> list[tuple[np.ndarray, np.ndarray, np.ndarray]]:\n    rng = np.random.default_rng(seed)\n    x_std_all = (x_raw - center) / scale\n    densities_by_iter: list[list[np.ndarray]] = [[] for _ in range(n_iter + 1)]\n    for _ in range(n_boot):\n        sample_std = rng.choice(x_std_all, size=len(x_std_all), replace=True)\n        trace_b = adam_normal_trace(sample_std, n_iter=n_iter)\n        for t, (mu, log_sigma, _loss) in enumerate(trace_b):\n            densities_by_iter[t].append(normal_density_from_std_params(grid_raw, center, scale, mu, log_sigma))\n\n    bands: list[tuple[np.ndarray, np.ndarray, np.ndarray]] = []\n    for densities in densities_by_iter:\n        arr = np.vstack(densities)\n        bands.append((np.quantile(arr, 0.05, axis=0), np.mean(arr, axis=0), np.quantile(arr, 0.95, axis=0)))\n    return bands\n\n\ndef linear_loss(x_std: np.ndarray, y_std: np.ndarray, intercept: float, slope: float) -> float:\n    resid = intercept + slope * x_std - y_std\n    return float(np.mean(resid**2))\n\n\ndef adam_linear_trace(\n    x_std: np.ndarray,\n    y_std: np.ndarray,\n    n_iter: int = 55,\n    lr: float = 0.10,\n    start_intercept: float = -1.2,\n    start_slope: float = -0.9,\n) -> list[tuple[float, float, float]]:\n    """Adam steps for least-squares regression on standardized x/y."""\n    params = np.array([start_intercept, start_slope], dtype=float)\n    m = np.zeros_like(params)\n    v = np.zeros_like(params)\n    beta1, beta2, eps = 0.9, 0.999, 1e-8\n    trace: list[tuple[float, float, float]] = []\n\n    for step in range(n_iter + 1):\n        intercept, slope = float(params[0]), float(params[1])\n        trace.append((intercept, slope, linear_loss(x_std, y_std, intercept, slope)))\n\n        resid = intercept + slope * x_std - y_std\n        grad = np.array([2 * np.mean(resid), 2 * np.mean(resid * x_std)], dtype=float)\n        m = beta1 * m + (1 - beta1) * grad\n        v = beta2 * v + (1 - beta2) * (grad**2)\n        m_hat = m / (1 - beta1 ** (step + 1))\n        v_hat = v / (1 - beta2 ** (step + 1))\n        params -= lr * m_hat / (np.sqrt(v_hat) + eps)\n    return trace\n\n\ndef predict_line_raw(\n    x_grid_raw: np.ndarray,\n    x_center: float,\n    x_scale: float,\n    y_center: float,\n    y_scale: float,\n    intercept: float,\n    slope: float,\n) -> np.ndarray:\n    x_grid_std = (x_grid_raw - x_center) / x_scale\n    y_pred_std = intercept + slope * x_grid_std\n    return y_center + y_scale * y_pred_std\n\n\ndef linear_bootstrap_trace_bands(\n    x_raw: np.ndarray,\n    y_raw: np.ndarray,\n    x_grid_raw: np.ndarray,\n    x_center: float,\n    x_scale: float,\n    y_center: float,\n    y_scale: float,\n    n_iter: int = 55,\n    n_boot: int = 90,\n    seed: int = 0,\n) -> list[tuple[np.ndarray, np.ndarray, np.ndarray]]:\n    rng = np.random.default_rng(seed)\n    x_std_all = (x_raw - x_center) / x_scale\n    y_std_all = (y_raw - y_center) / y_scale\n    preds_by_iter: list[list[np.ndarray]] = [[] for _ in range(n_iter + 1)]\n    n = len(x_raw)\n    for _ in range(n_boot):\n        idx = rng.integers(0, n, size=n)\n        trace_b = adam_linear_trace(x_std_all[idx], y_std_all[idx], n_iter=n_iter)\n        for t, (intercept, slope, _loss) in enumerate(trace_b):\n            preds_by_iter[t].append(\n                predict_line_raw(x_grid_raw, x_center, x_scale, y_center, y_scale, intercept, slope)\n            )\n\n    bands: list[tuple[np.ndarray, np.ndarray, np.ndarray]] = []\n    for preds in preds_by_iter:\n        arr = np.vstack(preds)\n        bands.append((np.quantile(arr, 0.05, axis=0), np.mean(arr, axis=0), np.quantile(arr, 0.95, axis=0)))\n    return bands\n'))

cells.append(nbf.v4.new_markdown_cell('## 1. データ固定: 単一正規分布がヒストグラムへフィットしていく様子\n\n"\n    "- **データ**: Palmer Penguins の `body_mass_g` を全フレームで固定表示。\n"\n    "- **推論**: 標準化した体重 $z$ に対して、正規分布の負の対数尤度を Adam で最小化する。\n"\n    "- **見方**: 初期値では密度曲線がヒストグラムからずれている。step が進むにつれて $\\mu, \\sigma$ が更新され、曲線がデータ分布に沿う。\n"\n    "- **90%帯**: 各 step で、固定データからのブートストラップ推論 trace に基づく密度帯を描く。\n"\n'))

cells.append(nbf.v4.new_code_cell('def make_fixed_data_normal_inference_gif() -> Path:\n    x_raw = penguins["body_mass_g"].dropna().to_numpy(float)\n    center = float(x_raw.mean())\n    scale = float(x_raw.std(ddof=1))\n    x_std = (x_raw - center) / scale\n\n    n_iter = 55\n    trace = adam_normal_trace(x_std, n_iter=n_iter)\n    x_min, x_max = x_raw.min() - 350, x_raw.max() + 350\n    grid = np.linspace(x_min, x_max, 360)\n    bins = np.linspace(x_min, x_max, 24)\n    bands_by_iter = normal_bootstrap_trace_bands(\n        x_raw, grid, center, scale, n_iter=n_iter, n_boot=90, seed=505\n    )\n    band_area_by_iter = [float(np.trapezoid(hi - lo, grid)) for lo, _mid, hi in bands_by_iter]\n    print(\n        "normal fixed-data band area by step: "\n        f"first={band_area_by_iter[0]:.4f}, "\n        f"middle={band_area_by_iter[len(band_area_by_iter)//2]:.4f}, "\n        f"last={band_area_by_iter[-1]:.4f}"\n    )\n\n    frames: list[np.ndarray] = []\n    max_band_height = max(float(hi.max()) for lo, _mid, hi in bands_by_iter)\n    y_top = max(max_band_height, 0.001) * 1.25\n    for t, (mu, log_sigma, nll) in enumerate(trace):\n        sigma_std = float(np.exp(log_sigma))\n        density = normal_density_from_std_params(grid, center, scale, mu, log_sigma)\n        lo, mid, hi = bands_by_iter[t]\n\n        fig, ax = plt.subplots(figsize=(8.7, 5.2), constrained_layout=True)\n        ax.hist(x_raw, bins=bins, density=True, color="0.78", alpha=0.50, label="固定データのヒストグラム")\n        ax.fill_between(grid, lo, hi, color="#DD8452", alpha=0.22, label="このstepの90%帯")\n        ax.plot(grid, density, color="#C44E52", lw=2.7, label="現在の推定正規分布")\n        ax.axvline(center + scale * mu, color="#C44E52", lw=1.2, ls=":", alpha=0.8)\n        ax.set_title("1. データ固定: 推論stepごとの正規分布フィッティング")\n        ax.set_xlabel("body_mass_g")\n        ax.set_ylabel("density")\n        ax.set_xlim(x_min, x_max)\n        ax.set_ylim(0, y_top)\n        add_note(\n            ax,\n            f"step {t}/{n_iter}\\nデータは全フレーム固定\\nμ={center + scale * mu:,.0f} g\\nσ={scale * sigma_std:,.0f} g\\nNLL/obs={nll:.3f}\\n90%帯面積={band_area_by_iter[t]:.4f}",\n        )\n        ax.legend(loc="upper right", frameon=True)\n        frames.append(fig_to_frame(fig))\n        plt.close(fig)\n\n    return save_gif(frames, GIF_DIR / "05_fixed_data_normal_inference_steps.gif", fps=9)\n\n\ngif_05 = make_fixed_data_normal_inference_gif()\ngif_05\n'))

cells.append(nbf.v4.new_markdown_cell('## 2. データ固定: 単回帰線が散布図へフィットしていく様子\n\n"\n    "- **データ**: Palmer Penguins の `flipper_length_mm` と `body_mass_g` を全フレームで固定表示。\n"\n    "- **推論**: 標準化した $x, y$ に対して、平均二乗誤差を Adam で最小化する。\n"\n    "- **見方**: 初期値では回帰線がデータ雲と反対方向/低い位置にある。step が進むにつれて傾きと切片が更新され、点群の中心を通る線になる。\n"\n    "- **90%帯**: 各 step で、固定データからのブートストラップ推論 trace に基づく回帰平均線の帯を描く。\n"\n'))

cells.append(nbf.v4.new_code_cell('def make_fixed_data_linear_inference_gif() -> Path:\n    df = penguins[["flipper_length_mm", "body_mass_g", "species"]].dropna().copy()\n    x_raw = df["flipper_length_mm"].to_numpy(float)\n    y_raw = df["body_mass_g"].to_numpy(float)\n    x_center, x_scale = float(x_raw.mean()), float(x_raw.std(ddof=1))\n    y_center, y_scale = float(y_raw.mean()), float(y_raw.std(ddof=1))\n    x_std = (x_raw - x_center) / x_scale\n    y_std = (y_raw - y_center) / y_scale\n\n    n_iter = 55\n    trace = adam_linear_trace(x_std, y_std, n_iter=n_iter)\n    x_grid = np.linspace(x_raw.min() - 4, x_raw.max() + 4, 240)\n    bands_by_iter = linear_bootstrap_trace_bands(\n        x_raw, y_raw, x_grid, x_center, x_scale, y_center, y_scale, n_iter=n_iter, n_boot=90, seed=606\n    )\n    band_width_by_iter = [float(np.mean(hi - lo)) for lo, _mid, hi in bands_by_iter]\n    print(\n        "linear fixed-data mean band width by step: "\n        f"first={band_width_by_iter[0]:.2f}, "\n        f"middle={band_width_by_iter[len(band_width_by_iter)//2]:.2f}, "\n        f"last={band_width_by_iter[-1]:.2f}"\n    )\n\n    # 比較用の最小二乗解\n    X = np.column_stack([np.ones_like(x_std), x_std])\n    ols_intercept, ols_slope = np.linalg.lstsq(X, y_std, rcond=None)[0]\n    ols_pred = predict_line_raw(x_grid, x_center, x_scale, y_center, y_scale, ols_intercept, ols_slope)\n\n    frames: list[np.ndarray] = []\n    for t, (intercept, slope, loss) in enumerate(trace):\n        pred = predict_line_raw(x_grid, x_center, x_scale, y_center, y_scale, intercept, slope)\n        lo, mid, hi = bands_by_iter[t]\n\n        fig, ax = plt.subplots(figsize=(8.7, 5.2), constrained_layout=True)\n        ax.scatter(x_raw, y_raw, s=32, color="#4C72B0", alpha=0.65, edgecolor="white", linewidth=0.35, label="固定データ")\n        ax.fill_between(x_grid, lo, hi, color="#55A868", alpha=0.22, label="このstepの90%帯")\n        ax.plot(x_grid, pred, color="#2C7F4F", lw=2.8, label="現在の推定回帰線")\n        ax.plot(x_grid, ols_pred, color="0.25", lw=1.4, ls=":", label="最小二乗解（到達先）")\n        ax.set_title("2. データ固定: 推論stepごとの単回帰フィッティング")\n        ax.set_xlabel("flipper_length_mm")\n        ax.set_ylabel("body_mass_g")\n        ax.set_xlim(x_grid.min(), x_grid.max())\n        ax.set_ylim(y_raw.min() - 500, y_raw.max() + 500)\n        raw_slope = y_scale * slope / x_scale\n        raw_intercept = y_center + y_scale * intercept - raw_slope * x_center\n        add_note(\n            ax,\n            f"step {t}/{n_iter}\\nデータは全フレーム固定\\ny = {raw_intercept:,.0f} + {raw_slope:.1f} x\\nMSE(std)={loss:.3f}\\n90%帯平均幅={band_width_by_iter[t]:.1f} g",\n        )\n        ax.legend(loc="upper left", frameon=True)\n        frames.append(fig_to_frame(fig))\n        plt.close(fig)\n\n    return save_gif(frames, GIF_DIR / "06_fixed_data_linear_inference_steps.gif", fps=9)\n\n\ngif_06 = make_fixed_data_linear_inference_gif()\ngif_06\n'))

cells.append(nbf.v4.new_markdown_cell('## 3. 作成したGIF\n\n"\n    "ノートを実行すると、以下のファイルが生成される。\n\n"\n    "1. `outputs/gifs/05_fixed_data_normal_inference_steps.gif`\n"\n    "2. `outputs/gifs/06_fixed_data_linear_inference_steps.gif`\n\n"\n    "Jupyter 上では次のセルでまとめて表示する。\n"\n'))

cells.append(nbf.v4.new_code_cell('from IPython.display import HTML, display\n\nitems = [\n    ("1. 固定データでの単一分布フィッティング", gif_05),\n    ("2. 固定データでの単回帰フィッティング", gif_06),\n]\nhtml = ["<div style=\'display:grid; grid-template-columns: 1fr; gap: 24px;\'>"]\nfor title, path in items:\n    rel = path.relative_to(PROJECT_ROOT).as_posix()\n    html.append(\n        f"<section><h3>{title}</h3><p><code>{rel}</code></p>"\n        f"<img src=\'../{rel}\' style=\'max-width: 920px; width: 100%; border:1px solid #ddd;\'>"\n        f"</section>"\n    )\nhtml.append("</div>")\ndisplay(HTML("\\n".join(html)))\n'))

cells.append(nbf.v4.new_markdown_cell('## 4. まとめ\n\n"\n    "- 前ノートブックの `データが増えるにつれて安定する` アニメーションとは異なり、このノートでは **全データを最初から固定** している。\n"\n    "- 単一分布フィットでは、正規分布の $\\mu, \\sigma$ が NLL を下げながらヒストグラムへ近づく。\n"\n    "- 単回帰では、切片 $\\alpha$ と傾き $\\beta$ が MSE を下げながら散布図の中心へ近づく。\n"\n    "- 90%帯も各 step の推論 trace から作っているため、最終 step の帯を全フレームへ固定コピーしていない。\n"\n'))

nb["cells"] = cells
nbf.write(nb, NOTEBOOK_PATH)
print(NOTEBOOK_PATH)
